INSERT INTO faqs (category, question, answer) VALUES
('SHIPPING', 'How long does shipping take?', 'Most orders are processed within 2-3 business days. Domestic shipping usually takes 5-7 days, while international shipping can take 10-14 days depending on your location.'),
('RETURN', 'What is your return policy?', 'We accept returns within 14 days of delivery. Items must be in their original condition, unworn, and with all tags attached. Please visit our Returns page for more details.'),
('ORDER_TRACKING', 'How do I track my order?', 'Once your order has shipped, you will receive an email with a tracking number and a link to follow its progress via our courier partner.'),
('OTHERS', 'Do you ship internationally?', 'Yes, we ship to most countries worldwide. Shipping costs and delivery times vary by destination. Import duties may apply upon arrival.'),
('SIZING', 'What sizing should I choose?', 'Most of our pieces are designed with an oversized, boxy fit. We recommend taking your standard size for the intended look, or sizing down for a more tailored fit.');
